# Concrete shape implementations
from geometry import ShapeBase, IMeasurable, IDrawable, Point

# Rectangle class with multiple interfaces
class Rectangle(ShapeBase, IDrawable):
    # Instance fields
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @override
    def measure(self) -> float:
        return self.width * self.height

    @override
    def get_name(self) -> str:
        return "Rectangle"

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    @override
    def draw(self) -> str:
        return "Drawing {}x{} rectangle".format(self.width, self.height)

# Circle class
class Circle(ShapeBase, IDrawable):
    radius: float
    center: Point

    def __init__(self, center: Point, radius: float):
        self.center = center
        self.radius = radius

    @override
    def measure(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_name(self) -> str:
        return "Circle"

    @override
    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

    @override
    def draw(self) -> str:
        return "Drawing circle at ({}, {})".format(self.center.x, self.center.y)

