# Utility functions and helpers
from geometry import Point, IMeasurable
from shapes import Rectangle, Circle

# Type alias for shape factory function
type ShapeFactory = () -> IMeasurable

# Static counter class
class Counter:
    @static
    count: int = 0

    @static
    def increment() -> int:
        Counter.count = Counter.count + 1
        return Counter.count

    @static
    def get_count() -> int:
        return Counter.count

    @static
    def reset() -> None:
        Counter.count = 0

# Factory functions
def create_default_rectangle() -> Rectangle:
    return Rectangle(10.0, 5.0)

def create_default_circle() -> Circle:
    p: Point = Point(0.0, 0.0)
    return Circle(p, 5.0)

# Function to process shapes with a callback
def process_shapes(shapes: list[IMeasurable], processor: (IMeasurable) -> float) -> list[float]:
    results: list[float] = list()
    for shape in shapes:
        results.append(processor(shape))
    return results

# Compute total area of all shapes
def total_area(shapes: list[IMeasurable]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.measure()
    return total
